# Test int with float operations (type coercion)

# int + float
print(1 + 2.5)    # 3.5
print(10 + 0.5)   # 10.5

# int - float
print(5 - 1.5)    # 3.5
print(10 - 0.25)  # 9.75

# int * float
print(3 * 2.5)    # 7.5
print(4 * 0.5)    # 2.0

# int // float
print(7 // 2.0)   # 3.0
print(10 // 3.0)  # 3.0

# int % float
print(7 % 2.5)    # 2.0
print(10 % 3.5)   # 3.0

# int ** float (power)
print(pow(4, 0.5))  # 2.0
print(pow(8, 0.5))  # 2.828...
